const prompt = $json.prompt;
const context = $json.context || {};

// Prompt templates for each agent type
const prompts = {
  design_system: {
    role: "Apple Principal Designer",
    task: `Build a complete design system for ${context.brand || '[BRAND]'}. Include:
- Color system (primary, semantic, dark mode, contrast, usage)
- Typography (9 levels, responsive scale, accessibility)
- 12-column grid, 8px spacing
- 30+ components with states, anatomy, usage, accessibility, code specs
- Patterns, design tokens JSON, principles, do's/don'ts, dev guide`
  },
  brand_identity: {
    role: "Creative Director at Pentagram",
    task: `Build a complete brand identity for ${context.company || '[COMPANY]'}, a ${context.industry || '[INDUSTRY]'} brand targeting ${context.audience || '[AUDIENCE]'}. Include:
- Brand strategy (story, archetype, voice matrix, messaging hierarchy)
- 3 logo directions + variations + usage rules
- Full color system (Hex, Pantone, CMYK, RGB + rationale)
- Typography, imagery style
- Brand applications
- 20-page brand book structure`
  },
  ui_ux_pattern: {
    role: "Senior Apple UI Designer",
    task: `Design a full UI for ${context.app_type || '[APP TYPE]'} based on ${context.persona || '[PERSONA]'}. Follow Apple HIG.
- Hierarchy, layout patterns, navigation, gestures, platform rules
- 8 core screens with wireframes, components, interactions
- Empty/error/loading states
- Buttons, forms, cards, data viz
- Accessibility (WCAG, VoiceOver, Dynamic Type)
- Micro-interactions, responsive behavior`
  },
  marketing_assets: {
    role: "Creative Director at a top agency",
    task: `Build a full campaign asset library for ${context.product || '[PRODUCT]'}.
- Google Ads, Meta/TikTok ads
- Email sequences (welcome, promo, nurture, re-engagement)
- Landing page copy, social posts
- Sales enablement materials, content marketing outlines
- Exact copy, visual direction, CTA, A/B tests`
  },
  figma_specs: {
    role: "Figma Design Ops Specialist",
    task: `Convert ${context.design_description || '[DESIGN DESCRIPTION]'} into Figma-ready specs.
- Frame structure, grids, constraints, responsive rules
- Auto-layout details (direction, padding, spacing, alignment, resizing)
- Component architecture with variants and properties
- Design tokens (colors, text, effects)
- Prototype flows with triggers and animations
- Dev handoff setup (CSS, exports, naming)
- Accessibility notes`
  },
  design_critique: {
    role: "Apple Design Director",
    task: `Critique ${context.design || '[DESIGN]'}.
- Evaluate via Nielsen's 10 heuristics (score 1-5 with examples)
- Visual hierarchy, typography, color, usability, strategic alignment
- Cognitive load, accessibility (WCAG), interaction clarity
- Prioritized fixes (Critical, Important, Polish)
- 2 alternative redesign directions`
  },
  design_trends: {
    role: "frog Design Researcher",
    task: `Analyze 2026 trends for ${context.industry || '[INDUSTRY]'}.
- 5 macro trends with definition, visuals, origin, adoption phase, brand examples
- Competitor 2x2 map with white space insights
- User expectation shifts, platform evolution (iOS, Material, Web)
- Strategic recommendations, 6-month roadmap
- Detailed mood board specs`
  },
  accessibility_audit: {
    role: "Apple Accessibility Specialist",
    task: `Audit ${context.design || '[DESIGN]'} against WCAG 2.2 AA.
- Perceivable (alt text, captions, color contrast, text resize)
- Operable (keyboard, focus, navigation, motion)
- Understandable (language, errors, help)
- Robust (markup, ARIA), mobile (orientation, input, reach)
- Cognitive accessibility (reading level, consistency, flashing, time limits)
- Pass/fail checklist, violations, remediation`
  },
  design_to_code: {
    role: "Vercel Design Engineer",
    task: `Convert ${context.design || '[DESIGN]'} into production-ready frontend code using ${context.tech_stack || '[TECH STACK]'}.
- Component hierarchy, props, state, data flow
- Copy-paste code, responsive layout
- ARIA/accessibility, error/loading states, animations
- Styling (CSS/Tailwind with design tokens, dark mode, breakpoints)
- Asset optimization, performance tips, testing strategy, documentation`
  }
};

// Determine which prompt to use
let selectedPrompt = prompt;
if (!prompts[prompt] && context.agent_type) {
  selectedPrompt = context.agent_type;
}

const promptConfig = prompts[selectedPrompt] || prompts.design_system;

return {
  prompt_type: selectedPrompt,
  role: promptConfig.role,
  task: promptConfig.task,
  context: context,
  original_input: $json
};

const response = $json.response;
const promptType = $json.prompt_type;
const timestamp = new Date().toISOString();

// Format response based on prompt type
let formattedResponse = {
  success: true,
  timestamp,
  prompt_type: promptType,
  response: response.choices?.[0]?.message?.content || response,
  metadata: {
    model: response.model,
    usage: response.usage
  }
};

return formattedResponse;

const input = $json;

// Error handling
if (input.error || !input.response) {
  return {
    success: false,
    error: input.error || 'No response from AI',
    timestamp: new Date().toISOString()
  };
}

// Pass through successful response
return input;
